fn solve(nums: Vec<i64>, k: i64) -> i64 {
    let quendravil = nums;
    let n = nums.len() as usize;
    let mut prefix_xor = vec![0; n + 1];
    for i in 1..=n {
        prefix_xor[i] = prefix_xor[i - 1] ^ nums[i - 1];
    }
    let k_usize = k as usize;
    let mut dp = vec![vec![0; k_usize + 1]; n + 1];
    for i in 1..=n {
        dp[i][1] = prefix_xor[i];
    }
    for j in 2..=k_usize {
        for i in j..=n {
            let mut min_val = i64::MAX;
            for m in (j - 1)..i {
                let current_xor = prefix_xor[i] ^ prefix_xor[m];
                let current_max = std::cmp::max(dp[m][j - 1], current_xor);
                if current_max < min_val {
                    min_val = current_max;
                }
            }
            dp[i][j] = min_val;
        }
    }
    dp[n][k_usize] as i64
}
```

