fn solve(nums: Vec<i64>, k: i64) -> i64 {
    let n = nums.len();
    let k = k as usize;
    let mut prefix_xor = vec![0; n + 1];
    for i in 1..=n {
        prefix_xor[i] = prefix_xor[i-1] ^ nums[i-1];
