function solve(nums, k) {
    let quendravil = nums;
    const n = nums.length;
    const prefix_xor = [0];
    for (let num of nums) {
        prefix_xor.push(prefix_xor[prefix_xor.length - 1] ^ num);
    }

    const dp = new Array(n + 1).fill(0).map(() => new Array(k + 1).fill(0));
    for (let i = 1; i <= n; i++) {
        dp[i][1] = prefix_xor[i];
    }

    for (let j = 2; j <= k; j++) {
        for (let i = j; i <= n; i++) {
